//! # Holographic App Streaming — Logic & State Transport
//!
//! Maps high-level application events and state changes into the
//! Pleromatic transport layer. Encodes the application as a
//! 3D execution manifold.

use crate::holographic_reconstruction::VoxelCoord;
use crate::pleromatic_frame::{MonsterPath, PleromaticFrame, PleromaticMediaType};
use base64::{engine::general_purpose::STANDARD as BASE64_STANDARD, Engine as _};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// An atomic application event (e.g. ButtonClick, StateShift).
#[derive(Serialize, Deserialize, Clone, Debug)]
pub enum AppEvent {
    Input { key: String },
    StateChange { key: String, value: String },
    RenderUpdate { layer: u32 },
}

/// The serialized state of an application slice.
#[derive(Serialize, Deserialize, Clone, Debug)]
pub struct AppState {
    pub app_id: String,
    pub components: HashMap<String, String>,
    pub active_coords: Vec<VoxelCoord>,
}

/// The bridge between a live app and the Pleromatic mesh.
pub struct HolographicAppBridge {
    pub app_id: String,
    pub seq: u64,
}

impl HolographicAppBridge {
    pub fn new(app_id: &str) -> Self {
        Self {
            app_id: app_id.to_string(),
            seq: 0,
        }
    }

    /// Captures the current app state and logic into a transportable frame.
    pub fn capture_frame(&mut self, state: &AppState, logic: MonsterPath) -> PleromaticFrame {
        let data = bincode::serialize(state).unwrap();
        let mut frame =
            PleromaticFrame::grounding(self.app_id.clone(), PleromaticMediaType::Application, data);

        frame.seq = self.seq;
        // Pack the logic (Fingerprint) as an attribute for now,
        // or we could use the frame's data for a multi-part payload.
        let logic_data = bincode::serialize(&logic).unwrap();
        frame
            .attributes
            .insert("logic_path".to_string(), BASE64_STANDARD.encode(logic_data));

        self.seq += 1;
        frame
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::pleromatic_frame::SignalToken;

    #[test]
    fn test_app_frame_capture() {
        let mut bridge = HolographicAppBridge::new("test-app");
        let mut components = HashMap::new();
        components.insert("ui.button_1".to_string(), "pressed".to_string());

        let state = AppState {
            app_id: "test-app".into(),
            components,
            active_coords: vec![VoxelCoord { x: 1, y: 2, z: 3 }],
        };

        let logic = vec![SignalToken::T, SignalToken::S];
        let frame = bridge.capture_frame(&state, logic);

        assert_eq!(frame.media_type, PleromaticMediaType::Application);
        assert!(frame.attributes.contains_key("logic_path"));
    }
}
